mapper.select:
SELECT find_stat.totalDetections, dp_stat.truePositiveCount, dp_stat.falsePositiveCount, CASE WHEN find_stat.totalDetections > 0 THEN ROUND(dp_stat.truePositiveCount * 100.0 / find_stat.totalDetections, 2) ELSE 0 END AS truePositiveRate, CASE WHEN find_stat.totalDetections > 0 THEN ROUND(dp_stat.falsePositiveCount * 100.0 / find_stat.totalDetections, 2) ELSE 0 END AS falsePositiveRate, dp_stat.processedCount, (find_stat.totalDetections - dp_stat.processedCount) AS unprocessedCount FROM ( SELECT COUNT(*) AS totalDetections FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
) find_stat, ( SELECT SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount FROM pi_data_processing dp INNER JOIN pi_targets t ON dp.TARGET_ID = t.TARGET_ID WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
) dp_stat

choose.when:
SELECT s.DATA_TYPE AS datatype, COUNT(*) AS totalCount, 0 AS truePositiveCount, 0 AS falsePositiveCount, 0 AS processedCount, COUNT(*) AS unprocessedCount, 0 AS truePositiveRate FROM pi_summary s INNER JOIN pi_targets t ON s.TARGET_ID = t.TARGET_ID AND s.AP_NO = t.AP_NO WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND s.REGDATE >= #{startDate}
AND s.REGDATE <= #{endDate}
GROUP BY s.DATA_TYPE ORDER BY totalCount DESC

mapper.select:
SELECT DATE_FORMAT(f.REGDATE, '%Y-%m') AS month, COUNT(*) AS totalCount, 0 AS truePositiveCount, 0 AS falsePositiveCount, 0 AS processedCount, 0 AS unprocessedCount FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO WHERE t.TARGET_USE = 'Y'
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
/* [튜닝] 날짜 범위 미지정 시 최근 24개월로 기본 제한 → 전체 테이블 스캔 방지 */
AND f.REGDATE >= DATE_FORMAT(DATE_SUB(NOW(), INTERVAL 24 MONTH), '%Y-%m-01')
GROUP BY DATE_FORMAT(f.REGDATE, '%Y-%m') ORDER BY month ASC
